      innerStrokeRect.x,
      innerStrokeRect.y,
      innerStrokeRect.w,
      innerStrokeRect.h,
      clampCornerRadius(Math.max(0, radius - strokeInset), innerStrokeRect.w, innerStrokeRect.h)
