    top: 'rgba(49,94,71,0.96)',
    bottom: 'rgba(22,48,34,0.92)',
    stroke: 'rgba(133,224,162,0.34)',
    accent: '#68D29B',
    labelColor: '#F5FFF7',
    subColor: 'rgba(222,241,231,0.78)',
    labelPx: u * 0.46,
    labelMinPx: u * 0.25,
